const funnel = $input.all()[0]?.json || {};
const activity = $input.all()[1]?.json || {};
const msgs = $input.all()[2]?.json || {};
const kpis = $input.all()[3]?.json || {};
const hotLeads = $input.all()[4]?.json ? $input.all().slice(4).map(i => i.json) : [];

// ── Validación de datos ──
const safeNum = (v) => {
  const n = Number(v);
  return (isNaN(n) || v === null || v === undefined) ? 0 : n;
};
const safePct = (v) => {
  const n = Number(v);
  return (isNaN(n) || v === null || v === undefined) ? '0.0' : n.toFixed(1);
};

const today = new Date().toLocaleDateString('es-AR', {dateStyle:'long'});
const weekAgo = new Date(Date.now() - 7*24*60*60*1000).toLocaleDateString('es-AR', {day:'2-digit',month:'2-digit'});
const todayShort = new Date().toLocaleDateString('es-AR', {day:'2-digit',month:'2-digit'});

// ── Hot leads formatting ──
let hotLeadsSection = '';
if (hotLeads.length > 0) {
  hotLeadsSection = hotLeads.map((l, i) =>
    `${i+1}. ${l.name || 'Sin nombre'} | Score: ${safeNum(l.ai_engagement_score)} | ${l.status}`
  ).join('
');
} else {
  hotLeadsSection = 'Sin hot leads activos esta semana';
}

const report = `📊 *REPORTE SEMANAL OUTREACH*
📅 Semana ${weekAgo} al ${todayShort} — ${today}

━━━━━━━━━━━━━━━━━━
🔢 *FUNNEL ACTUAL*
━━━━━━━━━━━━━━━━━━
├ 🆕 NEW: ${safeNum(funnel.funnel_new)}
├ 📞 CONTACTED: ${safeNum(funnel.funnel_contacted)}
├ 💬 IN_CONVERSATION: ${safeNum(funnel.funnel_in_conv)}
├ ⭐ QUALIFIED: ${safeNum(funnel.funnel_qualified)}
├ 🏗️ ONBOARDING: ${safeNum(funnel.funnel_onboarding)}
├ 🏆 WON: ${safeNum(funnel.funnel_won)}
├ 🥶 COLD: ${safeNum(funnel.funnel_cold)}
├ ❌ LOST: ${safeNum(funnel.funnel_lost)}
└ 🗑️ DISCARDED: ${safeNum(funnel.funnel_discarded)}
📊 Total: ${safeNum(funnel.total)}

━━━━━━━━━━━━━━━━━━
📈 *ACTIVIDAD ESTA SEMANA*
━━━━━━━━━━━━━━━━━━
├ Contactados: ${safeNum(activity.contacted_this_week)}
├ Conversaciones: ${safeNum(activity.conversations_this_week)}
├ Calificados: ${safeNum(activity.qualified_this_week)}
├ En Onboarding: ${safeNum(activity.onboarding_this_week)}
├ Ganados: ${safeNum(activity.won_this_week)}
├ Perdidos: ${safeNum(activity.lost_this_week)}
└ 🔥 Hot Leads activos: ${safeNum(activity.hot_leads_active)}

━━━━━━━━━━━━━━━━━━
📨 *MENSAJERÍA (7d)*
━━━━━━━━━━━━━━━━━━
├ Enviados: ${safeNum(msgs.msgs_sent_week)}
├ Recibidos: ${safeNum(msgs.msgs_received_week)}
├ Respondedores únicos: ${safeNum(msgs.unique_responders)}
└ ⚠️ Errores: ${safeNum(msgs.errors_week)}

━━━━━━━━━━━━━━━━━━
🎯 *KPIs*
━━━━━━━━━━━━━━━━━━
├ Conversión: ${safePct(kpis.conversion_rate)}%
├ Engagement: ${safePct(kpis.engagement_rate)}%
├ Avg AI Score: ${kpis.avg_ai_score || 'N/A'}
└ Avg Follow-ups to Win: ${kpis.avg_followups_to_win || 'N/A'}

━━━━━━━━━━━━━━━━━━
🔥 *TOP HOT LEADS*
━━━━━━━━━━━━━━━━━━
${hotLeadsSection}`;

// Validar que el reporte no está vacío
if (!report || report.length < 100) {
  throw new Error('Reporte generado vacío o incompleto');
}

return [{ json: { report, validated: true, charCount: report.length } }];

